Find the bug in this JavaScript function and explain what's wrong:

function getAverage(numbers) {
  let sum = 0;
  for (let i = 1; i <= numbers.length; i++) {
    sum += numbers[i];
  }
  return sum / numbers.length;
}

What is the bug? What would happen if you called getAverage([10, 20, 30])? What is the fix?

Refactor this JavaScript code to use async/await instead of nested callbacks. Explain what you changed and why it's better:

function loadUserData(userId, callback) {
  getUser(userId, function(err, user) {
    if (err) { callback(err); return; }
    getPosts(user.id, function(err, posts) {
      if (err) { callback(err); return; }
      getComments(posts[0].id, function(err, comments) {
        if (err) { callback(err); return; }
        callback(null, { user, posts, comments });
      });
    });
  });
}
